            toStringOutput.Add($"MessagingServiceSid = {this.MessagingServiceSid ?? "null"}");
            toStringOutput.Add($"Sid = {this.Sid ?? "null"}");
            toStringOutput.Add($"DateSent = {this.DateSent ?? "null"}");
            toStringOutput.Add($"DateCreated = {this.DateCreated ?? "null"}");
            toStringOutput.Add($"ErrorCode = {(this.ErrorCode == null ? "null" : this.ErrorCode.ToString())}");
            toStringOutput.Add($"PriceUnit = {this.PriceUnit ?? "null"}");
            toStringOutput.Add($"ApiVersion = {this.ApiVersion ?? "null"}");
            toStringOutput.Add($"SubresourceUris = {(this.SubresourceUris == null ? "null" : this.SubresourceUris.ToString())}");

            additionalProperties?
                .Select(kvp => $"[{kvp.Key}] = {kvp.Value.ToString(Formatting.None)}")
                .ToList()
                .ForEach(toStringOutput.Add);
        }
    }
}